import json
import sys
from pathlib import Path

# Add src to path
SRC = Path(__file__).resolve().parents[2] / "src"
sys.path.insert(0, str(SRC))

import pytest

from azure_kinect_comfyui.capture.models import Joint, JointId, TrackingState
from azure_kinect_comfyui.pose.mapping import MappedPose25, map_kinect_to_body25


FIXTURES_DIR = Path(__file__).resolve().parents[2] / "fixtures" / "skeletons"


def _load_fixture(filename: str) -> dict:
    """Load a skeleton fixture JSON file."""
    path = FIXTURES_DIR / filename
    return json.loads(path.read_text(encoding="utf-8"))


def _joints_from_fixture(fixture: dict) -> dict:
    """Extract Joint objects from a skeleton fixture's pose.joints dict."""
    joints = {}
    for key, jraw in fixture["pose"]["joints"].items():
        jid = int(key)
        joints[jid] = Joint(
            joint_id=JointId(jid),
            position=tuple(jraw["position"]),
            state=TrackingState(jraw.get("state", 0)),
        )
    return joints


@pytest.fixture
def neutral_standing_fixture():
    return _load_fixture("neutral_standing.json")


@pytest.fixture
def neutral_standing_joints(neutral_standing_fixture):
    return _joints_from_fixture(neutral_standing_fixture)


@pytest.fixture
def missing_joints_fixture():
    return _load_fixture("missing_joints.json")


@pytest.fixture
def missing_joints_joints(missing_joints_fixture):
    return _joints_from_fixture(missing_joints_fixture)


@pytest.fixture
def neutral_standing_pose(neutral_standing_joints, neutral_standing_fixture):
    pose_data = neutral_standing_fixture["pose"]
    return map_kinect_to_body25(
        neutral_standing_joints,
        frame_id=pose_data["frame_id"],
        timestamp_us=pose_data["timestamp_us"],
    )


@pytest.fixture
def missing_joints_pose(missing_joints_joints, missing_joints_fixture):
    pose_data = missing_joints_fixture["pose"]
    return map_kinect_to_body25(
        missing_joints_joints,
        frame_id=pose_data["frame_id"],
        timestamp_us=pose_data["timestamp_us"],
    )

